insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'Solve for x: 3x + 7 = 34.', 'x ज्ञात कीजिए: 3x + 7 = 34.', '3x = 34-7 = 27. Divide by 3: x = 9. Therefore, answer = 9.', 'A linear equation is solved by undoing operations in reverse order: remove the constant, then remove the coefficient of x. Final answer is 9.', '3x = 34-7 = 27। 3 से divide करें: x = 9। अतः answer = 9।', 'Linear equation में operations reverse order में undo होते हैं: पहले constant हटाएँ, फिर x का coefficient हटाएँ। Final answer 9 है।', 'EASY', array['algebra','linear-equations']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
