insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 8, 'If x + y = 18 and x - y = 12, find x.', 'यदि x + y = 18 और x - y = 12, तो x ज्ञात कीजिए।', 'Add both equations: 2x = 18+12 = 30. Hence x = 15. Therefore, answer = 15.', 'Adding x+y and x-y cancels y and leaves 2x, so the target variable is isolated directly. Final answer is 15.', 'दोनों equations add करें: 2x = 18+12 = 30। इसलिए x = 15। अतः answer = 15।', 'x+y और x-y add करने पर y cancel होता है और 2x बचता है। Final answer 15 है।', 'MEDIUM', array['algebra','simultaneous-equations']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
